"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[83747],{64152(e,t,i){i.r(t),i.d(t,{assets:()=>l,contentTitle:()=>o,default:()=>f,frontMatter:()=>r,metadata:()=>n,toc:()=>c});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 7 and IAS 7/supply-chain-financing-arrangements--38094fceff","title":"Supply Chain Financing Arrangements\u2014Reverse Factoring","description":"December 2020","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 7 and IAS 7/Supply Chain Financing Arrangements\u2014Reverse Factoring.md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 7 and IAS 7","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-7-and-ias-7-23a3130c76/supply-chain-financing-arrangements--38094fceff","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-7-and-ias-7-23a3130c76/supply-chain-financing-arrangements--38094fceff","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"supply-chain-financing-arrangements--38094fceff","title":"Supply Chain Financing Arrangements\u2014Reverse Factoring","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-7-and-ias-7-23a3130c76/supply-chain-financing-arrangements--38094fceff","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Special Purpose Acquisition Companies (SPAC)\uFF1AAccounting for Warrants at Acquisition","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-2-and-ias-32-56a750466e/special-purpose-acquisition-companie-b7f4772d91"},"next":{"title":"Credit Enhancement in the Measurement of Expected CreditLosses (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/credit-enhancement-in-the-measuremen-7083a6f464"}}');var a=i(74848),s=i(28453);let r={id:"supply-chain-financing-arrangements--38094fceff",title:"Supply Chain Financing Arrangements\u2014Reverse Factoring",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-7-and-ias-7-23a3130c76/supply-chain-financing-arrangements--38094fceff",sidebar_position:1},o="Supply Chain Financing Arrangements\u2014Reverse Factoring",l={},c=[{value:"Presentation in the statement of financial position",id:"presentation-in-the-statement-of-financial-position",level:2},{value:"Derecognition of a financial liability",id:"derecognition-of-a-financial-liability",level:2},{value:"Presentation in the statement of cash flows",id:"presentation-in-the-statement-of-cash-flows",level:2},{value:"Notes to the financial statements",id:"notes-to-the-financial-statements",level:2}];function h(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"supply-chain-financing-arrangementsreverse-factoring",children:"Supply Chain Financing Arrangements\u2014Reverse Factoring"})}),"\n",(0,a.jsx)(t.p,{children:"December 2020"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about reverse factoring arrangements. Specifically, the request asked:"}),"\n",(0,a.jsx)(t.p,{children:"a. how an entity presents liabilities to pay for goods or services received when the related invoices are part of a reverse factoring arrangement; and\nb. what information about reverse factoring arrangements an entity is required to disclose in its financial statements."}),"\n",(0,a.jsx)(t.p,{children:"In a reverse factoring arrangement, a financial institution agrees to pay amounts an entity owes to the entity\u2019s suppliers and the entity agrees to pay the financial institution at the same date as, or a date later than, suppliers are paid."}),"\n",(0,a.jsx)(t.h2,{id:"presentation-in-the-statement-of-financial-position",children:"Presentation in the statement of financial position"}),"\n",(0,a.jsx)(t.p,{children:"IAS 1 Presentation of Financial Statements specifies how an entity is required to present its liabilities in the statement of financial position."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 54 of IAS 1 requires an entity to present \u2018trade and other payables\u2019 separately from other financial liabilities. \u2018Trade and other payables\u2019 are sufficiently different in nature or function from other financial liabilities to warrant separate presentation (paragraph 57 of IAS 1). Paragraph 55 of IAS 1 requires an entity to present additional line items (including by disaggregating the line items listed in paragraph 54) when such presentation is relevant to an understanding of the entity\u2019s financial position. Consequently, an entity is required to determine whether to present liabilities that are part of a reverse factoring arrangement:"}),"\n",(0,a.jsx)(t.p,{children:"a. within trade and other payables;\nb. within other financial liabilities; or\nc. as a line item separate from other items in its statement of financial position."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 11(a) of IAS 37 Provisions, Contingent Liabilities and Contingent Assets states that \u2018trade payables are liabilities to pay for goods or services that have been received or supplied and have been invoiced or formally agreed with the supplier\u2019. Paragraph 70 of IAS 1 explains that \u2018some current liabilities, such as trade payables\u2026 are part of the working capital used in the entity\u2019s normal operating cycle\u2019. The Committee therefore concluded that an entity presents a financial liability as a trade payable only when it:"}),"\n",(0,a.jsx)(t.p,{children:"a. represents a liability to pay for goods or services;\nb. is invoiced or formally agreed with the supplier; and\nc. is part of the working capital used in the entity\u2019s normal operating cycle."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 29 of IAS 1 requires an entity to \u2018present separately items of a dissimilar nature or function unless they are immaterial\u2019. Paragraph 57 specifies that line items are included in the statement of financial position when the size, nature or function of an item (or aggregation of similar items) is such that separate presentation is relevant to an understanding of the entity\u2019s financial position. Accordingly, the Committee concluded that, applying IAS 1, an entity presents liabilities that are part of a reverse factoring arrangement:"}),"\n",(0,a.jsx)(t.p,{children:"a. as part of \u2018trade and other payables\u2019 only when those liabilities have a similar nature and function to trade payables\u2014for example, when those liabilities are part of the working capital used in the entity\u2019s normal operating cycle.\nb. separately when the size, nature or function of those liabilities makes separate presentation relevant to an understanding of the entity\u2019s financial position. In assessing whether it is required to present such liabilities separately (including whether to disaggregate trade and other payables), an entity considers the amounts, nature and timing of those liabilities (paragraphs 55 and 58 of IAS 1)."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that an entity assessing whether to present liabilities that are part of a reverse factoring arrangement separately might consider factors including, for example:"}),"\n",(0,a.jsx)(t.p,{children:"a. whether additional security is provided as part of the arrangement that would not be provided without the arrangement.\nb. the extent to which the terms of liabilities that are part of the arrangement differ from the terms of the entity\u2019s trade payables that are not part of the arrangement."}),"\n",(0,a.jsx)(t.h2,{id:"derecognition-of-a-financial-liability",children:"Derecognition of a financial liability"}),"\n",(0,a.jsx)(t.p,{children:"An entity assesses whether and when to derecognise a liability that is (or becomes) part of a reverse factoring arrangement applying the derecognition requirements in IFRS 9 Financial Instruments."}),"\n",(0,a.jsx)(t.p,{children:"An entity that derecognises a trade payable to a supplier and recognises a new financial liability to a financial institution applies IAS 1 in determining how to present that new liability in its statement of financial position (see \u2018Presentation in the statement of financial position\u2019)."}),"\n",(0,a.jsx)(t.h2,{id:"presentation-in-the-statement-of-cash-flows",children:"Presentation in the statement of cash flows"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 6 of IAS 7 Statement of Cash Flows defines:"}),"\n",(0,a.jsx)(t.p,{children:"a. operating activities as \u2018the principal revenue-producing activities of the entity and other activities that are not investing or financing activities\u2019; and\nb. financing activities as \u2018activities that result in changes in the size and composition of the contributed equity and borrowings of the entity\u2019."}),"\n",(0,a.jsx)(t.p,{children:"An entity that has entered into a reverse factoring arrangement determines how to classify cash flows under the arrangement, typically as cash flows from operating activities or cash flows from financing activities. The Committee observed that an entity\u2019s assessment of the nature of the liabilities that are part of the arrangement may help in determining whether the related cash flows arise from operating or financing activities. For example, if the entity considers the related liability to be a trade or other payable that is part of the working capital used in the entity\u2019s principal revenue-producing\nactivities, the entity presents cash outflows to settle the liability as arising from operating activities in its statement of cash flows. In contrast, if the entity considers that the related liability is not a trade or other payable because the liability represents borrowings of the entity, the entity presents cash outflows to settle the liability as arising from financing activities in its statement of cash flows."}),"\n",(0,a.jsx)(t.p,{children:"Investing and financing transactions that do not require the use of cash or cash equivalents are excluded from an entity\u2019s statement of cash flows (paragraph 43 of IAS 7). Consequently, if a cash inflow and cash outflow occur for an entity when an invoice is factored as part of a reverse factoring arrangement, the entity presents those cash flows in its statement of cash flows. If no cash inflow or cash outflow occurs for an entity in a financing transaction, the entity discloses the transaction elsewhere in the financial statements in a way that provides all the relevant information about the financing activity (paragraph 43 of IAS 7)."}),"\n",(0,a.jsx)(t.h2,{id:"notes-to-the-financial-statements",children:"Notes to the financial statements"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 31 of IFRS 7 Financial Instruments: Disclosures requires an entity to provide information that enables users of its financial statements to evaluate the nature and extent of risks arising from financial instruments to which the entity is exposed. IFRS 7 defines liquidity risk as \u2018the risk that an entity will encounter difficulty in meeting obligations associated with financial liabilities that are settled by delivering cash or another financial asset\u2019. The Committee observed that reverse factoring arrangements often give rise to liquidity risk because:"}),"\n",(0,a.jsx)(t.p,{children:"a. the entity has concentrated a portion of its liabilities with one financial institution rather than a diverse group of suppliers. The entity may also obtain other sources of funding from the financial institution providing the reverse factoring arrangement. If the entity were to encounter any difficulty in meeting its obligations, such a concentration would increase the risk that the entity might have to pay a significant amount, at one time, to one counterparty.\nb. the entity may have become reliant on extended payment terms or the entity\u2019s supplier may have become accustomed to, or reliant on, earlier payment under the reverse factoring arrangement. If the financial institution were to withdraw the reverse factoring arrangement, that withdrawal could affect the entity\u2019s ability to settle liabilities when they are due, particularly if the entity were already in financial distress."}),"\n",(0,a.jsx)(t.p,{children:"Paragraphs 33\u201335 of IFRS 7 require an entity to disclose how exposures to risk arising from financial instruments, including liquidity risk, arise; the entity\u2019s objectives, policies and processes for managing the risk; summary quantitative data about the entity\u2019s exposure to liquidity risk at the end of the reporting period (including further information if this data is unrepresentative of the entity\u2019s exposure to liquidity risk during the period); and concentrations of risk. Paragraphs 39 and B11F of IFRS 7 specify further requirements and factors an entity might consider in providing liquidity risk disclosures."}),"\n",(0,a.jsx)(t.p,{children:"An entity applies judgement in determining whether to provide additional disclosures in the notes about the effect of reverse factoring arrangements on its financial position, financial performance and cash flows. The Committee observed that:"}),"\n",(0,a.jsx)(t.p,{children:"a. assessing how to present liabilities and cash flows related to reverse factoring arrangements may involve judgement. An entity discloses the judgements that management has made in this respect if they are among the judgements made that have the most significant effect on the amounts recognised in the financial statements (paragraph 122 of IAS 1).\nb. reverse factoring arrangements may have a material effect on an entity\u2019s financial statements. An entity provides information about reverse factoring arrangements in its financial statements to the extent that such information is relevant to an understanding of any of those financial statements (paragraph 112 of IAS 1)."}),"\n",(0,a.jsx)(t.p,{children:"The Committee noted that making materiality judgements involves both quantitative and qualitative considerations."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph 44A of IAS 7 requires an entity to provide \u2018disclosures that enable users of financial statements to evaluate changes in liabilities arising from financing activities, including both changes arising from cash flows and non-cash changes\u2019. The Committee noted that such disclosure is required for liabilities that are part of a reverse factoring arrangement if the cash flows for those liabilities were, or future cash flows will be, classified as cash flows from financing activities."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Standards provide an adequate basis for an entity to determine the presentation of liabilities that are part of reverse factoring arrangements, the presentation of the related cash flows, and the information to disclose in the notes about, for example, liquidity risks that arise in such arrangements. Consequently, the Committee decided not to add a standard-setting project on these matters to the work plan."})]})}function f(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(h,{...e})}):h(e)}},28453(e,t,i){i.d(t,{R:()=>r,x:()=>o});var n=i(96540);let a={},s=n.createContext(a);function r(e){let t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);